const payload = typeof $json.payload === 'string' ? JSON.parse($json.payload) : ($json.payload || {});
const template = String($json.template_key || '').trim();
const channel = String($json.channel || '').trim();

const activity = payload.nome_struttura || payload.nome_attivita || 'Zirèl';
const businessName = payload.business_name || payload.hotel_name || payload.nome_attivita || payload.nome_struttura || payload.nome_ristorante || payload.tenant_id || activity;

const recipientEmail = String(
  $json.recipient_email ||
  (channel === 'email_guest_appointment' || channel === 'email_guest_hotel' || channel === 'email_guest_restaurant' ? payload.email : '') ||
  payload.internal_email ||
  payload.billing_email ||
  payload.email ||
  ''
).trim().toLowerCase();

const statusLabel = ({
  confirmed: 'Confermata',
  confermata: 'Confermata',
  manual_review: 'Verifica manuale',
  rejected: 'Non disponibile',
  rifiutata: 'Non disponibile',
  annullata: 'Non disponibile',
  pending: 'In lavorazione',
  change_proposed: 'Proposta inviata',
})[String(payload.booking_status || payload.status || payload.availability_status || '').trim()] || 'In lavorazione';

const planCode = String(payload.billing_plan_code || '').trim().toLowerCase();
const cycleCode = String(payload.billing_cycle || '').trim().toLowerCase();
const planLabel = planCode === 'premium' ? 'Zirèl Core Premium' : planCode === 'base' ? 'Zirèl Core Base' : 'Piano Zirèl';
const cycleLabel = cycleCode === 'yearly' ? 'Annuale' : cycleCode === 'monthly' ? 'Mensile' : 'Non definito';
const dashboardUrl = String(payload.dashboard_url || 'https://dashboard.zirel.org?tab=abbonamento').trim();
const portalUrl = String(payload.portal_url || 'https://dashboard.zirel.org?tab=abbonamento').trim();

const formatDate = (value) => {
  if (!value) return 'N/D';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleDateString('it-IT', {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
    timeZone: 'Europe/Rome',
  });
};

const pad = (value) => String(value).padStart(2, '0');

const buildLocalDateTime = (dateValue, timeValue) => {
  const dateRaw = String(dateValue || '').trim();
  const timeRaw = String(timeValue || '').trim();
  if (!dateRaw || !timeRaw) return null;

  const [year, month, day] = dateRaw.split('-').map(Number);
  const [hour, minute] = timeRaw.split(':').map(Number);

  if (!year || !month || !day || Number.isNaN(hour) || Number.isNaN(minute)) return null;

  return { year, month, day, hour, minute };
};

const toCalendarStamp = (parts) =>
  parts ? `${parts.year}${pad(parts.month)}${pad(parts.day)}T${pad(parts.hour)}${pad(parts.minute)}00` : '';

const addMinutes = (parts, minutesToAdd) => {
  if (!parts) return null;
  const d = new Date(Date.UTC(parts.year, parts.month - 1, parts.day, parts.hour, parts.minute + minutesToAdd, 0));
  return {
    year: d.getUTCFullYear(),
    month: d.getUTCMonth() + 1,
    day: d.getUTCDate(),
    hour: d.getUTCHours(),
    minute: d.getUTCMinutes(),
  };
};

const toQueryString = (params) =>
  Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null && value !== '')
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
    .join('&');

const createGoogleCalendarUrl = ({ title, details, location, startDate, startTime, durationMinutes }) => {
  const start = buildLocalDateTime(startDate, startTime);
  if (!start) return '';
  const end = addMinutes(start, durationMinutes);

  const query = toQueryString({
    action: 'TEMPLATE',
    text: title,
    details,
    location,
    ctz: 'Europe/Rome',
    dates: `${toCalendarStamp(start)}/${toCalendarStamp(end)}`,
  });

  return `https://calendar.google.com/calendar/render?${query}`;
};

const createIcsUrl = ({ type, entityId, tenantId }) => {
  const webhookBase = 'https://primary-production-b2af.up.railway.app/webhook/zirel-calendar-ics';
  if (!type || !entityId || !tenantId) return '';

  const query = toQueryString({
    type,
    id: entityId,
    tenant_id: tenantId,
  });

  return `${webhookBase}?${query}`;
};

const renderActions = (actions = []) => {
  const safeActions = actions.filter((action) => action?.href && action?.label);
  if (!safeActions.length) return '';
  return `<div style="margin-top:20px;display:flex;flex-wrap:wrap;gap:12px;">${safeActions
    .map(
      (action) =>
        `<a href="${action.href}" style="display:inline-block;padding:12px 16px;border-radius:14px;text-decoration:none;font-weight:700;font-size:14px;background:${action.variant === 'secondary' ? '#ffffff' : '#ff8c42'};color:${action.variant === 'secondary' ? '#0f172a' : '#ffffff'};border:1px solid ${action.variant === 'secondary' ? '#cbd5e1' : '#ff8c42'};">${action.label}</a>`
    )
    .join('')}</div>`;
};

const renderShell = (title, intro, bodyRows, outro, actions = []) => {
  const rows = bodyRows
    .filter(Boolean)
    .map((row) => `<tr><td style="padding:12px 14px;border-bottom:1px solid #e5e7eb;width:38%;font-weight:600;color:#0f172a;">${row.label}</td><td style="padding:12px 14px;border-bottom:1px solid #e5e7eb;color:#334155;">${row.value}</td></tr>`)
    .join('');

  return `<div style="font-family:Helvetica,Arial,sans-serif;background:#f8fafc;padding:24px;color:#0f172a;">
    <div style="max-width:680px;margin:0 auto;background:#ffffff;border:1px solid #e2e8f0;border-radius:20px;overflow:hidden;">
      <div style="padding:24px 28px;background:linear-gradient(135deg,#0f3b52 0%,#ff8c42 100%);color:#ffffff;">
        <p style="margin:0 0 8px;font-size:12px;letter-spacing:0.18em;text-transform:uppercase;opacity:0.82;">Zirèl Notification Center</p>
        <h1 style="margin:0;font-size:28px;line-height:1.15;">${title}</h1>
      </div>
      <div style="padding:28px;">
        <p style="margin:0 0 18px;font-size:16px;line-height:1.6;color:#334155;">${intro}</p>
        <table style="width:100%;border-collapse:collapse;border:1px solid #e5e7eb;border-radius:16px;overflow:hidden;background:#fff;">${rows}</table>
        ${renderActions(actions)}
        <p style="margin:18px 0 0;font-size:15px;line-height:1.7;color:#334155;">${outro}</p>
      </div>
    </div>
  </div>`;
};

